#!/bin/bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-05-07

# Regression: workflows installing @anthropic-ai/claude-code with --ignore-scripts
# must also run the package's install.cjs to fetch the native binary.
# Without this, every `claude` invocation fast-fails with:
#   Error: claude native binary not installed.
# Background: PR #1620 / run 25443026871 — cc-triage logged parse_failed=true
# for 3 versions in 5 ms because the binary was missing.

set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
PROJECT_ROOT="$(cd "$SCRIPT_DIR/../.." && pwd)"

RED='\033[0;31m'
GREEN='\033[0;32m'
NC='\033[0m'

PASS=0
FAIL=0
log_pass() { echo -e "  ${GREEN}✓${NC} $1"; PASS=$((PASS + 1)); }
log_fail() { echo -e "  ${RED}✗${NC} $1 — $2"; FAIL=$((FAIL + 1)); }

echo "CC CLI install pattern"
echo "======================"

cd "$PROJECT_ROOT"

shopt -s nullglob
# Only count uncommented `npm install ... @anthropic-ai/claude-code ... --ignore-scripts`
# command lines. Avoids false positives where a comment line documents why
# --ignore-scripts is intentionally NOT used (see ultrareview.yml:46-49).
INSTALL_CMD_RE='^[[:space:]]*[^#]*npm install.*@anthropic-ai/claude-code.*--ignore-scripts'

for wf in .github/workflows/*.yml .github/workflows/*.yaml; do
  [ -f "$wf" ] || continue
  if ! grep -q "@anthropic-ai/claude-code" "$wf"; then
    continue
  fi
  if ! grep -qE "$INSTALL_CMD_RE" "$wf"; then
    log_pass "$(basename "$wf"): installs without --ignore-scripts (postinstall runs)"
    continue
  fi
  if grep -q "install\.cjs" "$wf"; then
    log_pass "$(basename "$wf"): runs install.cjs after --ignore-scripts"
  else
    log_fail "$(basename "$wf")" \
      "uses --ignore-scripts but does not run install.cjs — \`claude\` will fail with \"native binary not installed\""
  fi
done

echo ""
echo "Results: ${PASS} passed, ${FAIL} failed"
[ "$FAIL" -eq 0 ]
